+    // Prefer an existing config file in the same order as config loading.
+    if let Ok(xdg_home) = std::env::var("XDG_CONFIG_HOME") {
+        if !xdg_home.trim().is_empty() {
+            let path = std::path::PathBuf::from(xdg_home)
