+                .join("config.toml");
+            if path.exists() {
+                return path;
+            }
+        }
+    }
+
+    if let Some(home) = dirs::home_dir() {
+        let path = home.join(".config").join("dcg").join("config.toml");
+        if path.exists() {
+            return path;
+        }
+    }
+
+    if let Some(config_dir) = dirs::config_dir() {
+        let path = config_dir.join("dcg").join("config.toml");
